'use client'

import { useField } from '@payloadcms/ui'
import React from 'react'

export const LfrsStatusWidget: React.FC = () => {
  const { value } = useField<any>({ path: 'lfrs' })

  if (!value) {
    return null
  }

  return (
    <div style={{ marginBottom: '24px' }}>
      <h4
        style={{
          color: 'var(--theme-elevation-400)',
          fontSize: '14px',
          margin: '0 0 12px 0',
          textTransform: 'uppercase',
        }}
      >
        Interactions
      </h4>
      <div
        style={{
          background: 'var(--theme-elevation-50)',
          border: '1px solid var(--theme-elevation-100)',
          borderRadius: '4px',
          display: 'flex',
          flexDirection: 'column',
          gap: '8px',
          padding: '16px',
        }}
      >
        {typeof value.likesCount === 'number' && (
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>Likes:</span>
            <strong>{value.likesCount}</strong>
          </div>
        )}
        {typeof value.dislikesCount === 'number' && (
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>Dislikes:</span>
            <strong>{value.dislikesCount}</strong>
          </div>
        )}
        {typeof value.favouritesCount === 'number' && (
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>Favourites:</span>
            <strong>{value.favouritesCount}</strong>
          </div>
        )}
        {typeof value.ratingsCount === 'number' && (
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>Ratings:</span>
            <strong>
              {value.ratingsCount} (Avg: {value.ratingsAverage?.toFixed(1) || 0})
            </strong>
          </div>
        )}
        {typeof value.reviewsCount === 'number' && (
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>Reviews:</span>
            <strong>{value.reviewsCount}</strong>
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

import { usePayloadAPI } from '@payloadcms/ui'
import React from 'react'

export const ReviewModerationView: React.FC = () => {
  // We can fetch pending reviews
  const [{ data: reviewsData, isLoading: reviewsLoading }, { setParams: setReviewsParams }] =
    usePayloadAPI('/api/lfrs-reviews', {
      initialParams: {
        limit: 10,
        where: {
          status: {
            equals: 'pending',
          },
        },
      },
    })

  // We can fetch pending replies
  const [{ data: repliesData, isLoading: repliesLoading }, { setParams: setRepliesParams }] =
    usePayloadAPI('/api/lfrs-replies', {
      initialParams: {
        limit: 10,
        where: {
          status: {
            equals: 'pending',
          },
        },
      },
    })

  const handleApprove = async (collection: string, id: string) => {
    try {
      await fetch(`/api/${collection}/${id}`, {
        body: JSON.stringify({ status: 'approved' }),
        headers: { 'Content-Type': 'application/json' },
        method: 'PATCH',
      })
      // Refresh
      setReviewsParams((prev: any) => ({ ...prev }))
      setRepliesParams((prev: any) => ({ ...prev }))
    } catch (e) {
      console.error(e)
    }
  }

  const handleReject = async (collection: string, id: string) => {
    try {
      await fetch(`/api/${collection}/${id}`, {
        body: JSON.stringify({ status: 'rejected' }),
        headers: { 'Content-Type': 'application/json' },
        method: 'PATCH',
      })
      // Refresh
      setReviewsParams((prev: any) => ({ ...prev }))
      setRepliesParams((prev: any) => ({ ...prev }))
    } catch (e) {
      console.error(e)
    }
  }

  return (
    <div style={{ margin: '0 auto', maxWidth: '1200px', padding: '2rem' }}>
      <h1>LFRs Moderation Queue</h1>
      <p style={{ color: 'var(--theme-elevation-400)' }}>
        Review and moderate pending reviews and replies.
      </p>

      <section style={{ marginTop: '2rem' }}>
        <h2>Pending Reviews ({reviewsData?.totalDocs || 0})</h2>
        {reviewsLoading ? (
          <div>Loading...</div>
        ) : reviewsData?.docs?.length > 0 ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {reviewsData.docs.map((doc: any) => (
              <div
                key={doc.id}
                style={{
                  background: 'var(--theme-elevation-50)',
                  border: '1px solid var(--theme-elevation-200)',
                  borderRadius: '4px',
                  padding: '1rem',
                }}
              >
                <div
                  style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}
                >
                  <strong>
                    {doc.title || 'No title'} (Score: {doc.score})
                  </strong>
                  <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button
                      onClick={() => handleApprove('lfrs-reviews', doc.id)}
                      style={{
                        background: '#0070f3',
                        border: 'none',
                        borderRadius: '4px',
                        color: 'white',
                        cursor: 'pointer',
                        padding: '0.5rem 1rem',
                      }}
                    >
                      Approve
                    </button>
                    <button
                      onClick={() => handleReject('lfrs-reviews', doc.id)}
                      style={{
                        background: '#e00',
                        border: 'none',
                        borderRadius: '4px',
                        color: 'white',
                        cursor: 'pointer',
                        padding: '0.5rem 1rem',
                      }}
                    >
                      Reject
                    </button>
                  </div>
                </div>
                <p>{doc.body}</p>
                <div style={{ color: 'var(--theme-elevation-400)', fontSize: '0.8rem' }}>
                  User: {typeof doc.user === 'object' ? doc.user?.email || doc.user?.id : doc.user}{' '}
                  | Target: {doc.targetCollection} ({doc.targetDoc})
                </div>
              </div>
            ))}
          </div>
        ) : (
          <p>No pending reviews.</p>
        )}
      </section>

      <section style={{ marginTop: '3rem' }}>
        <h2>Pending Replies ({repliesData?.totalDocs || 0})</h2>
        {repliesLoading ? (
          <div>Loading...</div>
        ) : repliesData?.docs?.length > 0 ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {repliesData.docs.map((doc: any) => (
              <div
                key={doc.id}
                style={{
                  background: 'var(--theme-elevation-50)',
                  border: '1px solid var(--theme-elevation-200)',
                  borderRadius: '4px',
                  padding: '1rem',
                }}
              >
                <div
                  style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}
                >
                  <strong>
                    Reply to Review ID:{' '}
                    {typeof doc.review === 'object' ? doc.review?.id : doc.review}
                  </strong>
                  <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button
                      onClick={() => handleApprove('lfrs-replies', doc.id)}
                      style={{
                        background: '#0070f3',
                        border: 'none',
                        borderRadius: '4px',
                        color: 'white',
                        cursor: 'pointer',
                        padding: '0.5rem 1rem',
                      }}
                    >
                      Approve
                    </button>
                    <button
                      onClick={() => handleReject('lfrs-replies', doc.id)}
                      style={{
                        background: '#e00',
                        border: 'none',
                        borderRadius: '4px',
                        color: 'white',
                        cursor: 'pointer',
                        padding: '0.5rem 1rem',
                      }}
                    >
                      Reject
                    </button>
                  </div>
                </div>
                <p>{doc.body}</p>
                <div style={{ color: 'var(--theme-elevation-400)', fontSize: '0.8rem' }}>
                  User: {typeof doc.user === 'object' ? doc.user?.email || doc.user?.id : doc.user}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <p>No pending replies.</p>
        )}
      </section>
    </div>
  )
}

'use client'

import React, { useState } from 'react'

import styles from './styles/lfrs.module.css'

export interface LfrsFavouriteProps {
  apiBase?: string
  className?: string
  initialFavourited?: boolean
  onAuthError?: () => void
  onToggle?: (favourited: boolean) => void
  targetCollection: string
  targetDoc: string
}

const BookmarkIcon = ({ active }: { active?: boolean }) => (
  <svg fill={active ? "currentColor" : "none"} stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" viewBox="0 0 24 24">
    <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
  </svg>
)

export const LfrsFavourite: React.FC<LfrsFavouriteProps> = ({
  apiBase = '/api',
  className = '',
  initialFavourited = false,
  onAuthError,
  onToggle,
  targetCollection,
  targetDoc,
}) => {
  const [loading, setLoading] = useState(false)
  const [favourited, setFavourited] = useState(initialFavourited)

  const handleToggle = async () => {
    if (loading) {return}
    
    // Optimistic update
    const previousState = favourited
    setFavourited(!favourited)
    
    try {
      setLoading(true)
      const res = await fetch(`${apiBase}/lfrs/favourite`, {
        body: JSON.stringify({ id: targetDoc, collection: targetCollection }),
        headers: { 'Content-Type': 'application/json' },
        method: 'POST',
      })
      
      if (!res.ok) {
        if (res.status === 401 && onAuthError) {
          onAuthError()
        }
        throw new Error('API Error')
      }
      
      const data = await res.json()
      
      // Sync with real data
      setFavourited(data.favourited ?? false)
      onToggle?.(data.favourited ?? false)
      
    } catch (e) {
      // Revert on error
      setFavourited(previousState)
    } finally {
      setLoading(false)
    }
  }

  return (
    <button
      className={`${styles.toggleButton} ${favourited ? styles.favouriteActive : ''} ${className}`}
      disabled={loading}
      onClick={handleToggle}
      title={favourited ? 'Remove from favourites' : 'Add to favourites'}
      type="button"
    >
      <BookmarkIcon active={favourited} />
      <span>{favourited ? 'Favourited' : 'Favourite'}</span>
    </button>
  )
}

'use client'

import React, { useState } from 'react'

import styles from './styles/lfrs.module.css'

export interface LfrsLikeDislikeProps {
  apiBase?: string
  className?: string
  dislikesEnabled?: boolean
  initialDisliked?: boolean
  initialDislikesCount?: number
  initialLiked?: boolean
  initialLikesCount?: number
  onAuthError?: () => void
  onToggle?: (state: { disliked: boolean; dislikesCount: number; liked: boolean; likesCount: number }) => void
  targetCollection: string
  targetDoc: string
}

const ThumbsUpIcon = () => (
  <svg viewBox="0 0 24 24">
    <path d="M14 9V5a3 3 0 0 0-3-3l-4 9v11h11.28a2 2 0 0 0 2-1.7l1.38-9a2 2 0 0 0-2-2.3zM7 22H4a2 2 0 0 1-2-2v-7a2 2 0 0 1 2-2h3" />
  </svg>
)

const ThumbsDownIcon = () => (
  <svg viewBox="0 0 24 24">
    <path d="M10 15v4a3 3 0 0 0 3 3l4-9V2H5.72a2 2 0 0 0-2 1.7l-1.38 9a2 2 0 0 0 2 2.3zm7-13h3a2 2 0 0 1 2 2v7a2 2 0 0 1-2 2h-3" />
  </svg>
)

export const LfrsLikeDislike: React.FC<LfrsLikeDislikeProps> = ({
  apiBase = '/api',
  className = '',
  dislikesEnabled = false,
  initialDisliked = false,
  initialDislikesCount = 0,
  initialLiked = false,
  initialLikesCount = 0,
  onAuthError,
  onToggle,
  targetCollection,
  targetDoc,
}) => {
  const [loading, setLoading] = useState(false)
  const [liked, setLiked] = useState(initialLiked)
  const [disliked, setDisliked] = useState(initialDisliked)
  const [likesCount, setLikesCount] = useState(initialLikesCount)
  const [dislikesCount, setDislikesCount] = useState(initialDislikesCount)

  const handleToggle = async (type: 'dislike' | 'like') => {
    if (loading) {return}
    
    // Optimistic update
    const previousState = { disliked, dislikesCount, liked, likesCount }
    
    let newLiked = liked
    let newDisliked = disliked
    let newLikesCount = likesCount
    let newDislikesCount = dislikesCount
    
    if (type === 'like') {
      newLiked = !liked
      newLikesCount += newLiked ? 1 : -1
      if (newLiked && disliked) {
        newDisliked = false
        newDislikesCount -= 1
      }
    } else {
      newDisliked = !disliked
      newDislikesCount += newDisliked ? 1 : -1
      if (newDisliked && liked) {
        newLiked = false
        newLikesCount -= 1
      }
    }
    
    setLiked(newLiked)
    setDisliked(newDisliked)
    setLikesCount(newLikesCount)
    setDislikesCount(newDislikesCount)
    
    try {
      setLoading(true)
      const res = await fetch(`${apiBase}/lfrs/${type}`, {
        body: JSON.stringify({ id: targetDoc, collection: targetCollection }),
        headers: { 'Content-Type': 'application/json' },
        method: 'POST',
      })
      
      if (!res.ok) {
        if (res.status === 401 && onAuthError) {
          onAuthError()
        }
        throw new Error('API Error')
      }
      
      const data = await res.json()
      
      // Sync with real data
      setLiked(data.liked ?? false)
      setDisliked(data.disliked ?? false)
      setLikesCount(data.likesCount ?? 0)
      if (data.dislikesCount !== undefined) {
        setDislikesCount(data.dislikesCount)
      }
      
      onToggle?.({ 
        disliked: data.disliked ?? false, 
        dislikesCount: data.dislikesCount ?? 0, 
        liked: data.liked ?? false, 
        likesCount: data.likesCount ?? 0 
      })
      
    } catch (e) {
      // Revert on error
      setLiked(previousState.liked)
      setDisliked(previousState.disliked)
      setLikesCount(previousState.likesCount)
      setDislikesCount(previousState.dislikesCount)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className={`${styles.likeDislikeGroup} ${className}`} style={{ display: 'flex', gap: '8px' }}>
      <button
        aria-label={liked ? 'Unlike' : 'Like'}
        className={`${styles.toggleButton} ${liked ? styles.likeActive : ''}`}
        disabled={loading}
        onClick={() => handleToggle('like')}
        type="button"
      >
        <ThumbsUpIcon />
        <span>{likesCount}</span>
      </button>

      {dislikesEnabled && (
        <button
          aria-label={disliked ? 'Remove dislike' : 'Dislike'}
          className={`${styles.toggleButton} ${disliked ? styles.dislikeActive : ''}`}
          disabled={loading}
          onClick={() => handleToggle('dislike')}
          type="button"
        >
          <ThumbsDownIcon />
          <span>{dislikesCount}</span>
        </button>
      )}
    </div>
  )
}

