'use client'

import React, { useState } from 'react'

import styles from './styles/lfrs.module.css'

export interface LfrsRatingProps {
  className?: string
  icon?: string
  max?: number
  onChange?: (value: number) => void
  readonly?: boolean
  step?: number
  value?: number
}

const StarIcon = ({ active }: { active?: boolean }) => (
  <svg
    className={`${styles.ratingIcon} ${active ? styles.active : ''}`}
    viewBox="0 0 24 24"
  >
    <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
  </svg>
)

const HeartIcon = ({ active }: { active?: boolean }) => (
  <svg
    className={`${styles.ratingIcon} ${active ? styles.active : ''}`}
    viewBox="0 0 24 24"
  >
    <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z" />
  </svg>
)

export const LfrsRating: React.FC<LfrsRatingProps> = ({
  className = '',
  icon = 'star',
  max = 5,
  onChange,
  readonly = false,
  step: _step = 1,
  value = 0,
}) => {
  const [hoverValue, setHoverValue] = useState<null | number>(null)

  const renderIcon = (active: boolean) => {
    switch (icon) {
      case 'heart':
        return <HeartIcon active={active} />
      case 'star':
      default:
        return <StarIcon active={active} />
    }
  }

  const items = Array.from({ length: max }, (_, i) => i + 1)

  return (
    <div 
      className={`${styles.rating} ${readonly ? styles.ratingReadonly : ''} ${className}`}
      onMouseLeave={() => !readonly && setHoverValue(null)}
    >
      {items.map((item) => {
        const isActive = hoverValue !== null ? item <= hoverValue : item <= value
        return (
          <button
            key={item}
            onClick={() => !readonly && onChange?.(item)}
            onMouseEnter={() => !readonly && setHoverValue(item)}
            style={{ cursor: readonly ? 'default' : 'pointer', display: 'flex', border: 'none', background: 'transparent', padding: 0 }}
            type="button"
            aria-label={`Rate ${item} out of ${max}`}
          >
            {renderIcon(isActive)}
          </button>
        )
      })}
    </div>
  )
}

'use client'

import React from 'react'

import styles from './styles/lfrs.module.css'

export interface LfrsReplyCardProps {
  className?: string
  reply: any
}

export const LfrsReplyCard: React.FC<LfrsReplyCardProps> = ({ className = '', reply }) => {
  const authorName = reply.user?.name || reply.user?.email || 'Anonymous'
  const dateStr = new Date(reply.createdAt).toLocaleDateString()

  return (
    <div className={`${styles.replyCard} ${className}`}>
      <div className={styles.reviewHeader}>
        <div className={styles.reviewAuthor}>{authorName}</div>
        <div className={styles.reviewDate}>{dateStr}</div>
      </div>
      <p className={styles.reviewBody}>{reply.body}</p>
    </div>
  )
}

'use client'

import React, { useState } from 'react'

import { LfrsComposeReply } from './LfrsComposeReply.js'
import { LfrsRating } from './LfrsRating.js'
import { LfrsReplyCard } from './LfrsReplyCard.js'
import styles from './styles/lfrs.module.css'

export interface LfrsReviewCardProps {
  apiBase?: string
  className?: string
  onAuthError?: () => void
  onReplySuccess?: () => void
  ratingConfig: { icon: string; max: number; step: number }
  repliesEnabled?: boolean
  review: any
}

export const LfrsReviewCard: React.FC<LfrsReviewCardProps> = ({
  apiBase = '/api',
  className = '',
  onAuthError,
  onReplySuccess,
  ratingConfig,
  repliesEnabled = false,
  review,
}) => {
  const [isReplying, setIsReplying] = useState(false)

  const authorName = review.user?.name || review.user?.email || 'Anonymous'
  const dateStr = new Date(review.createdAt).toLocaleDateString()

  const handleReplySuccess = () => {
    setIsReplying(false)
    onReplySuccess?.()
  }

  return (
    <div className={`${styles.reviewCard} ${className}`}>
      <div className={styles.reviewHeader}>
        <div>
          <div className={styles.reviewAuthor}>{authorName}</div>
          <div style={{ marginTop: '4px' }}>
            <LfrsRating
              icon={ratingConfig.icon}
              max={ratingConfig.max}
              readonly
              step={ratingConfig.step}
              value={review.score}
            />
          </div>
        </div>
        <div className={styles.reviewDate}>{dateStr}</div>
      </div>

      {review.title && <h4 className={styles.reviewTitle}>{review.title}</h4>}
      <p className={styles.reviewBody}>{review.body}</p>

      {review.media && review.media.length > 0 && (
        <div className={styles.reviewMedia}>
          {review.media.map((item: any, idx: number) => {
            if (!item.file?.url) {return null}
            return (
              <img
                alt="Review attachment"
                className={styles.reviewMediaItem}
                key={idx}
                src={item.file.url}
              />
            )
          })}
        </div>
      )}

      {repliesEnabled && (
        <div className={styles.reviewActions}>
          <button
            className={styles.buttonText}
            onClick={() => setIsReplying(!isReplying)}
            type="button"
          >
            Reply
          </button>
        </div>
      )}

      {isReplying && (
        <div style={{ marginTop: '16px' }}>
          <LfrsComposeReply
            apiBase={apiBase}
            onAuthError={onAuthError}
            onCancel={() => setIsReplying(false)}
            onSuccess={handleReplySuccess}
            reviewId={review.id}
          />
        </div>
      )}

      {review.replies && review.replies.length > 0 && (
        <div style={{ marginTop: '16px' }}>
          {review.replies.map((reply: any) => (
            <LfrsReplyCard key={reply.id} reply={reply} />
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import React, { useCallback, useEffect, useState } from 'react'

import { LfrsComposeReview } from './LfrsComposeReview.js'
import { LfrsReviewCard } from './LfrsReviewCard.js'
import styles from './styles/lfrs.module.css'

export interface LfrsReviewsSectionProps {
  apiBase?: string
  className?: string
  onAuthError?: () => void
  targetCollection: string
  targetDoc: string
}

export const LfrsReviewsSection: React.FC<LfrsReviewsSectionProps> = ({
  apiBase = '/api',
  className = '',
  onAuthError,
  targetCollection,
  targetDoc,
}) => {
  const [statusLoading, setStatusLoading] = useState(true)
  const [reviewsLoading, setReviewsLoading] = useState(true)

  const [status, setStatus] = useState<any>(null)
  const [reviews, setReviews] = useState<any[]>([])

  const [page, setPage] = useState(1)
  const [totalPages, setTotalPages] = useState(1)

  const [showCompose, setShowCompose] = useState(false)

  const fetchStatus = useCallback(async () => {
    try {
      const res = await fetch(
        `${apiBase}/lfrs/status?collection=${targetCollection}&id=${targetDoc}`,
      )
      if (res.ok) {
        const data = await res.json()
        setStatus(data)
      }
    } catch (_) {
      // Ignore
    } finally {
      setStatusLoading(false)
    }
  }, [apiBase, targetCollection, targetDoc])

  const fetchReviews = useCallback(
    async (p = 1) => {
      try {
        setReviewsLoading(true)
        const res = await fetch(
          `${apiBase}/lfrs/interactions?collection=${targetCollection}&id=${targetDoc}&type=reviews&page=${p}&limit=10`,
        )
        if (res.ok) {
          const data = await res.json()
          if (p === 1) {
            setReviews(data.docs)
          } else {
            setReviews((prev) => [...prev, ...data.docs])
          }
          setTotalPages(data.totalPages)
          setPage(data.page)
        }
      } catch (e) {
        // Ignore
      } finally {
        setReviewsLoading(false)
      }
    },
    [apiBase, targetCollection, targetDoc],
  )

  useEffect(() => {
    void fetchStatus()
    void fetchReviews(1)
  }, [fetchStatus, fetchReviews])

  const handleReviewSuccess = () => {
    setShowCompose(false)
    void fetchStatus()
    void fetchReviews(1)
    // Dispatch an event so other components (like LfrsRatingSummary) know to refetch
    window.dispatchEvent(new Event('lfrs-review-added'))
  }

  if (statusLoading && reviewsLoading) {
    return <div className={`${styles.reviewsSection} ${className}`}>Loading reviews...</div>
  }

  const hasMyReview = !!status?.review

  return (
    <div className={`${styles.reviewsSection} ${className}`}>
      <div style={{ alignItems: 'center', display: 'flex', justifyContent: 'space-between' }}>
        <h2>Reviews</h2>
        {!hasMyReview && !showCompose && status && (
          <button
            className={`${styles.button} ${styles.buttonPrimary}`}
            onClick={() => setShowCompose(true)}
            type="button"
          >
            Write a Review
          </button>
        )}
      </div>

      {hasMyReview && !showCompose && (
        <div style={{ marginBottom: '24px' }}>
          <h3>Your Review</h3>
          <LfrsReviewCard
            apiBase={apiBase}
            onReplySuccess={() => fetchReviews(1)}
            ratingConfig={status.ratingConfig}
            repliesEnabled={status.repliesEnabled}
            review={status.review}
          />
          <button
            className={`${styles.button} ${styles.buttonSecondary}`}
            onClick={() => setShowCompose(true)}
            style={{ marginTop: '12px' }}
            type="button"
          >
            Edit Review
          </button>
        </div>
      )}

      {showCompose && status && (
        <div style={{ marginBottom: '24px' }}>
          <LfrsComposeReview
            apiBase={apiBase}
            initialData={status.review}
            mediaEnabled={status.mediaEnabled}
            onAuthError={onAuthError}
            onCancel={() => setShowCompose(false)}
            onSuccess={handleReviewSuccess}
            ratingConfig={status.ratingConfig}
            targetCollection={targetCollection}
            targetDoc={targetDoc}
          />
        </div>
      )}

      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
        {reviews
          .filter((r) => r.id !== status?.review?.id) // exclude own review if it's already shown above
          .map((review) => (
            <LfrsReviewCard
              apiBase={apiBase}
              key={review.id}
              onAuthError={onAuthError}
              onReplySuccess={() => fetchReviews(page)}
              ratingConfig={status?.ratingConfig || { icon: 'star', max: 5, step: 1 }}
              repliesEnabled={status?.repliesEnabled}
              review={review}
            />
          ))}

        {reviews.length === 0 && !hasMyReview && (
          <div style={{ color: 'var(--lfrs-text-muted)' }}>No reviews yet.</div>
        )}
      </div>

      {page < totalPages && (
        <div style={{ display: 'flex', justifyContent: 'center', marginTop: '16px' }}>
          <button
            className={`${styles.button} ${styles.buttonSecondary}`}
            disabled={reviewsLoading}
            onClick={() => fetchReviews(page + 1)}
            type="button"
          >
            {reviewsLoading ? 'Loading...' : 'Load More'}
          </button>
        </div>
      )}
    </div>
  )
}

import { APIError, type PayloadHandler, type PayloadRequest } from 'payload'

import type { SanitizedLfrsConfig } from '../types.js'

import { getEnabledFeatures } from '../utilities/getEnabledFeatures.js'
import { resolveFeatureAccess } from '../utilities/resolveFeatureAccess.js'

export const createDislikeEndpoint = (sanitized: SanitizedLfrsConfig): PayloadHandler => {
  return async (req: PayloadRequest) => {
    try {
      const body = req.json ? await req.json() : req.body
      const { id, collection } = body || {}

      if (!collection || !id) {
        throw new APIError('Missing collection or id', 400)
      }

      const collectionOptions = sanitized.collections[collection]
      if (!collectionOptions) {
        throw new APIError('LFRs is not enabled for this collection', 404)
      }

      const enabledFeatures = getEnabledFeatures(collectionOptions)
      if (!enabledFeatures.has('dislikes')) {
        throw new APIError('Dislikes are not enabled for this collection', 404)
      }

      let targetDoc: any
      try {
        targetDoc = await req.payload.findByID({
          id,
          collection,
          overrideAccess: true,
          req,
        })
      } catch (e) {
        throw new APIError('Target document not found', 404)
      }

      const accessResult = await resolveFeatureAccess({
        access: collectionOptions.dislikes,
        req,
        targetCollection: collection,
        targetDoc,
      })

      if (!accessResult.allowed) {
        throw new APIError(accessResult.reason || 'Forbidden', 403)
      }

      const userId = req.user?.id
      if (!userId) {
        throw new APIError('Authentication required', 401)
      }

      // Check if dislike exists
      const existingDislikes = await req.payload.find({
        collection: sanitized.collectionSlugs.dislikes,
        overrideAccess: true,
        req,
        where: {
          and: [
            { user: { equals: userId } },
            { targetCollection: { equals: collection } },
            { targetDoc: { equals: id } },
          ],
        },
      })

      let disliked = false

      if (existingDislikes.docs.length > 0) {
        // Delete existing dislike
        await req.payload.delete({
          id: existingDislikes.docs[0].id as string,
          collection: sanitized.collectionSlugs.dislikes,
          overrideAccess: true,
          req,
        })
        disliked = false
      } else {
        // Check mutual exclusivity with likes
        if (enabledFeatures.has('likes')) {
          const existingLikes = await req.payload.find({
            collection: sanitized.collectionSlugs.likes,
            overrideAccess: true,
            req,
            where: {
              and: [
                { user: { equals: userId } },
                { targetCollection: { equals: collection } },
                { targetDoc: { equals: id } },
              ],
            },
          })
          if (existingLikes.docs.length > 0) {
            await req.payload.delete({
              id: existingLikes.docs[0].id as string,
              collection: sanitized.collectionSlugs.likes,
              overrideAccess: true,
              req,
            })
          }
        }

        // Create new dislike
        await req.payload.create({
          collection: sanitized.collectionSlugs.dislikes,
          data: {
            targetCollection: collection,
            targetDoc: id,
            user: userId,
          },
          overrideAccess: true,
          req,
        })
        disliked = true
      }

      // Re-fetch target doc to get updated counts
      const updatedDoc = await req.payload.findByID({
        id,
        collection,
        overrideAccess: true,
        req,
      })

      const responseData: any = {
        disliked,
        dislikesCount: updatedDoc.lfrs?.dislikesCount || 0,
      }

      if (enabledFeatures.has('likes')) {
        responseData.likesCount = updatedDoc.lfrs?.likesCount || 0
      }

      return Response.json(responseData)
    } catch (err: any) {
      const status = err.status || 500
      return Response.json({ error: err.message || 'Internal Server Error' }, { status })
    }
  }
}

import { APIError, type PayloadHandler, type PayloadRequest } from 'payload'

import type { SanitizedLfrsConfig } from '../types.js'

import { getEnabledFeatures } from '../utilities/getEnabledFeatures.js'

export const createDistributionEndpoint = (sanitized: SanitizedLfrsConfig): PayloadHandler => {
  return async (req: PayloadRequest) => {
    try {
      const collection = req.query?.collection as string
      const id = req.query?.id as string

      if (!collection || !id) {
        throw new APIError('Missing collection or id query parameter', 400)
      }

      const collectionOptions = sanitized.collections[collection]
      if (!collectionOptions) {
        throw new APIError('LFRs is not enabled for this collection', 404)
      }

      const enabledFeatures = getEnabledFeatures(collectionOptions)
      const distribution: Record<string, number> = {}
      let totalScore = 0
      let count = 0

      const processScores = (docs: any[]) => {
        for (const doc of docs) {
          if (typeof doc.score === 'number') {
            const scoreStr = doc.score.toString()
            distribution[scoreStr] = (distribution[scoreStr] || 0) + 1
            totalScore += doc.score
            count++
          }
        }
      }

      // We use limit: 100000 which is effectively all for most realistic scenarios.
      // A more optimized approach would use DB aggregation, but this works cross-database.
      if (enabledFeatures.has('ratings')) {
        const ratings = await req.payload.find({
          collection: sanitized.collectionSlugs.ratings,
          limit: 100000,
          overrideAccess: true,
          req,
          where: {
            and: [
              { targetCollection: { equals: collection } },
              { targetDoc: { equals: id } },
            ],
          },
        })
        processScores(ratings.docs)
      }

      if (enabledFeatures.has('reviews')) {
        const where: any = {
          and: [
            { targetCollection: { equals: collection } },
            { targetDoc: { equals: id } },
          ],
        }
        
        if (sanitized.reviewModeration) {
          where.and.push({ status: { equals: 'approved' } })
        }

        const reviews = await req.payload.find({
          collection: sanitized.collectionSlugs.reviews,
          limit: 100000,
          overrideAccess: true,
          req,
          where,
        })
        processScores(reviews.docs)
      }

      const average = count > 0 ? Number((totalScore / count).toFixed(2)) : 0

      // Re-fetch target doc to use its cached counts if we want, but the spec says
      // "Returns count of ratings per score value — powers the Amazon-style rating breakdown bars"
      // and returns average, totalRatings.
      // So returning the computed values is fine.

      const distributionArray = []
      for (let s = 1; s <= sanitized.rating.max; s += sanitized.rating.step) {
        const scoreStr = s.toString()
        const countForScore = distribution[scoreStr] || 0
        distributionArray.push({
          count: countForScore,
          percentage: count > 0 ? (countForScore / count) * 100 : 0,
          score: s,
        })
      }

      return Response.json({
        averageScore: average,
        config: sanitized.rating,
        distribution: distributionArray,
        totalRatings: count,
      })
    } catch (err: any) {
      const status = err.status || 500
      return Response.json({ error: err.message || 'Internal Server Error' }, { status })
    }
  }
}

