import { APIError, type PayloadHandler, type PayloadRequest } from 'payload'

import type { SanitizedLfrsConfig } from '../types.js'

import { getEnabledFeatures } from '../utilities/getEnabledFeatures.js'
import { resolveFeatureAccess } from '../utilities/resolveFeatureAccess.js'

export const createReplyEndpoint = (sanitized: SanitizedLfrsConfig): PayloadHandler => {
  return async (req: PayloadRequest) => {
    try {
      const body = req.json ? await req.json() : req.body
      const { body: replyBody, reviewId } = body || {}

      if (!reviewId || !replyBody) {
        throw new APIError('Missing reviewId or body', 400)
      }

      let parentReview: any
      try {
        parentReview = await req.payload.findByID({
          id: reviewId,
          collection: sanitized.collectionSlugs.reviews,
          overrideAccess: true,
          req,
        })
      } catch (e) {
        throw new APIError('Parent review not found', 404)
      }

      const collection = parentReview.targetCollection
      const collectionOptions = sanitized.collections[collection]
      
      if (!collectionOptions) {
        throw new APIError('LFRs is not enabled for this collection', 404)
      }

      const enabledFeatures = getEnabledFeatures(collectionOptions)
      if (!enabledFeatures.has('replies')) {
        throw new APIError('Replies are not enabled for this collection', 404)
      }

      let targetDoc: any
      try {
        targetDoc = await req.payload.findByID({
          id: parentReview.targetDoc,
          collection,
          overrideAccess: true,
          req,
        })
      } catch (e) {
        throw new APIError('Target document not found', 404)
      }

      const accessResult = await resolveFeatureAccess({
        access: collectionOptions.replies,
        req,
        targetCollection: collection,
        targetDoc,
      })

      if (!accessResult.allowed) {
        throw new APIError(accessResult.reason || 'Forbidden', 403)
      }

      const userId = req.user?.id
      if (!userId) {
        throw new APIError('Authentication required', 401)
      }

      const dataToSave: any = {
        body: replyBody,
        review: reviewId,
        user: userId,
      }

      if (sanitized.reviewModeration) {
        dataToSave.status = 'pending'
      }

      const replyDoc = await req.payload.create({
        collection: sanitized.collectionSlugs.replies,
        data: dataToSave,
        overrideAccess: true, // We did the access check manually
        req,
      })

      // Fetch the updated review to get the new repliesCount
      const updatedReview = await req.payload.findByID({
        id: reviewId,
        collection: sanitized.collectionSlugs.reviews,
        overrideAccess: true,
        req,
      })

      return Response.json({
        repliesCount: updatedReview.repliesCount || 0,
        reply: replyDoc,
      })
    } catch (err: any) {
      const status = err.status || 500
      return Response.json({ error: err.message || 'Internal Server Error' }, { status })
    }
  }
}

export const deleteReplyEndpoint = (sanitized: SanitizedLfrsConfig): PayloadHandler => {
  return async (req: PayloadRequest) => {
    try {
      const body = req.json ? await req.json() : req.body
      const { replyId } = body || {}

      if (!replyId) {
        throw new APIError('Missing replyId', 400)
      }

      const userId = req.user?.id
      if (!userId) {
        throw new APIError('Authentication required', 401)
      }

      // Check access: own replies only, or admin
      // We can just rely on the collection's access control (which has delete: isOwnerOrAdmin)
      // by not overriding access.
      let deletedReply: any
      try {
        deletedReply = await req.payload.delete({
          id: replyId,
          collection: sanitized.collectionSlugs.replies,
          overrideAccess: false,
          req, 
        })
      } catch (err: any) {
        throw new APIError(err.message || 'Error deleting reply or forbidden', 403)
      }

      const reviewId = typeof deletedReply.review === 'object' && deletedReply.review !== null ? deletedReply.review.id : deletedReply.review;

      const updatedReview = await req.payload.findByID({
        id: reviewId as string,
        collection: sanitized.collectionSlugs.reviews,
        overrideAccess: true,
        req,
      })

      return Response.json({
        deleted: true,
        repliesCount: updatedReview.repliesCount || 0,
      })
    } catch (err: any) {
      const status = err.status || 500
      return Response.json({ error: err.message || 'Internal Server Error' }, { status })
    }
  }
}

import { APIError, type PayloadHandler, type PayloadRequest } from 'payload'

import type { SanitizedLfrsConfig } from '../types.js'

import { getEnabledFeatures } from '../utilities/getEnabledFeatures.js'
import { resolveFeatureAccess } from '../utilities/resolveFeatureAccess.js'

export const createReviewEndpoint = (sanitized: SanitizedLfrsConfig): PayloadHandler => {
  return async (req: PayloadRequest) => {
    try {
      const body = req.json ? await req.json() : req.body
      const { id, body: reviewBody, collection, media, score, title } = body || {}

      if (!collection || !id || !reviewBody || typeof score !== 'number') {
        throw new APIError('Missing collection, id, body, or valid score', 400)
      }

      const collectionOptions = sanitized.collections[collection]
      if (!collectionOptions) {
        throw new APIError('LFRs is not enabled for this collection', 404)
      }

      const enabledFeatures = getEnabledFeatures(collectionOptions)
      if (!enabledFeatures.has('reviews')) {
        throw new APIError('Reviews are not enabled for this collection', 404)
      }

      let targetDoc: any
      try {
        targetDoc = await req.payload.findByID({
          id,
          collection,
          overrideAccess: true,
          req,
        })
      } catch (e) {
        throw new APIError('Target document not found', 404)
      }

      const accessResult = await resolveFeatureAccess({
        access: collectionOptions.reviews,
        req,
        targetCollection: collection,
        targetDoc,
      })

      if (!accessResult.allowed) {
        throw new APIError(accessResult.reason || 'Forbidden', 403)
      }

      const userId = req.user?.id
      if (!userId) {
        throw new APIError('Authentication required', 401)
      }

      // Check if review exists
      const existingReviews = await req.payload.find({
        collection: sanitized.collectionSlugs.reviews,
        overrideAccess: true,
        req,
        where: {
          and: [
            { user: { equals: userId } },
            { targetCollection: { equals: collection } },
            { targetDoc: { equals: id } },
          ],
        },
      })

      const dataToSave: any = {
        body: reviewBody,
        score,
        title,
      }

      if (sanitized.mediaEnabled && Array.isArray(media)) {
        dataToSave.media = media.map((fileId) => ({ file: fileId }))
      }

      if (sanitized.reviewModeration) {
        dataToSave.status = 'pending'
      }

      let reviewDoc: any

      if (existingReviews.docs.length > 0) {
        // Update existing review
        reviewDoc = await req.payload.update({
          id: existingReviews.docs[0].id as string,
          collection: sanitized.collectionSlugs.reviews,
          data: dataToSave,
          overrideAccess: true,
          req,
        })
      } else {
        // Create new review
        dataToSave.user = userId
        dataToSave.targetCollection = collection
        dataToSave.targetDoc = id
        
        reviewDoc = await req.payload.create({
          collection: sanitized.collectionSlugs.reviews,
          data: dataToSave,
          overrideAccess: true,
          req,
        })
      }

      // Re-fetch target doc to get updated counts
      const updatedDoc = await req.payload.findByID({
        id,
        collection,
        overrideAccess: true,
        req,
      })

      return Response.json({
        review: reviewDoc,
        reviewsCount: updatedDoc.lfrs?.reviewsCount || 0,
      })
    } catch (err: any) {
      const status = err.status || 500
      return Response.json({ error: err.message || 'Internal Server Error' }, { status })
    }
  }
}

import { APIError, type PayloadHandler, type PayloadRequest } from 'payload'

import type { SanitizedLfrsConfig } from '../types.js'

import { getEnabledFeatures } from '../utilities/getEnabledFeatures.js'

export const createStatusEndpoint = (sanitized: SanitizedLfrsConfig): PayloadHandler => {
  return async (req: PayloadRequest) => {
    try {
      const collection = req.query?.collection as string
      const id = req.query?.id as string

      if (!collection || !id) {
        throw new APIError('Missing collection or id query parameter', 400)
      }

      const collectionOptions = sanitized.collections[collection]
      if (!collectionOptions) {
        throw new APIError('LFRs is not enabled for this collection', 404)
      }

      const userId = req.user?.id
      if (!userId) {
        throw new APIError('Authentication required', 401)
      }

      const enabledFeatures = getEnabledFeatures(collectionOptions)

      const response: any = {
        dislikesEnabled: enabledFeatures.has('dislikes'),
        mediaEnabled: sanitized.mediaEnabled,
        ratingConfig: sanitized.rating,
        repliesEnabled: enabledFeatures.has('replies'),
      }

      // Check if liked
      if (enabledFeatures.has('likes')) {
        const likes = await req.payload.find({
          collection: sanitized.collectionSlugs.likes,
          overrideAccess: true,
          req,
          where: {
            and: [
              { user: { equals: userId } },
              { targetCollection: { equals: collection } },
              { targetDoc: { equals: id } },
            ],
          },
        })
        response.liked = likes.docs.length > 0
      } else {
        response.liked = false
      }

      // Check if disliked
      if (enabledFeatures.has('dislikes')) {
        const dislikes = await req.payload.find({
          collection: sanitized.collectionSlugs.dislikes,
          overrideAccess: true,
          req,
          where: {
            and: [
              { user: { equals: userId } },
              { targetCollection: { equals: collection } },
              { targetDoc: { equals: id } },
            ],
          },
        })
        response.disliked = dislikes.docs.length > 0
      }

      // Check if favourited
      if (enabledFeatures.has('favourites')) {
        const favourites = await req.payload.find({
          collection: sanitized.collectionSlugs.favourites,
          overrideAccess: true,
          req,
          where: {
            and: [
              { user: { equals: userId } },
              { targetCollection: { equals: collection } },
              { targetDoc: { equals: id } },
            ],
          },
        })
        response.favourited = favourites.docs.length > 0
      } else {
        response.favourited = false
      }

      // Check rating
      if (enabledFeatures.has('ratings')) {
        const ratings = await req.payload.find({
          collection: sanitized.collectionSlugs.ratings,
          overrideAccess: true,
          req,
          where: {
            and: [
              { user: { equals: userId } },
              { targetCollection: { equals: collection } },
              { targetDoc: { equals: id } },
            ],
          },
        })
        response.rating = ratings.docs.length > 0 ? ratings.docs[0].score : null
      } else {
        response.rating = null
      }

      // Check review
      if (enabledFeatures.has('reviews')) {
        const reviews = await req.payload.find({
          collection: sanitized.collectionSlugs.reviews,
          overrideAccess: true,
          req,
          where: {
            and: [
              { user: { equals: userId } },
              { targetCollection: { equals: collection } },
              { targetDoc: { equals: id } },
            ],
          },
        })
        response.review = reviews.docs.length > 0 ? reviews.docs[0] : null
      } else {
        response.review = null
      }

      return Response.json(response)
    } catch (err: any) {
      const status = err.status || 500
      return Response.json({ error: err.message || 'Internal Server Error' }, { status })
    }
  }
}

import type { CollectionBeforeChangeHook } from 'payload'

import { APIError } from 'payload'

import type { SanitizedReviewMediaConfig } from '../types.js'

import { matchesAnyMimeType } from '../utilities/matchMimeType.js'

/**
 * Creates a beforeChange hook that validates review media attachments.
 *
 * Checks:
 * - File count does not exceed `maxFiles`
 * - Each file's MIME type matches at least one `allowedMimeTypes` pattern
 * - Each file's size does not exceed `maxFileSize`
 *
 * Only runs if reviewMedia config is valid. Returns null if media is disabled.
 */
export function createValidateReviewMedia(
  mediaConfig: null | SanitizedReviewMediaConfig,
): CollectionBeforeChangeHook | null {
  if (!mediaConfig) {
    return null
  }

  const { allowedMimeTypes, maxFiles, maxFileSize } = mediaConfig

  return async ({ data, req }) => {
    const media = data.media as Array<{ file: string }> | undefined

    if (!media || media.length === 0) {
      return data
    }

    // Check file count
    if (media.length > maxFiles) {
      throw new APIError(`Maximum of ${maxFiles} files allowed per review`, 400)
    }

    // Validate each file
    for (const entry of media) {
      const fileId = entry.file

      // Fetch the upload doc to check mimeType and filesize
      let uploadDoc: Record<string, unknown>
      try {
        uploadDoc = (await req.payload.findByID({
          id: fileId,
          collection: mediaConfig.uploadCollection,
          depth: 0,
          req,
        })) as Record<string, unknown>
      } catch {
        throw new APIError(`Media file "${fileId}" not found in upload collection`, 400)
      }

      // Check MIME type
      const mimeType = uploadDoc.mimeType as string
      if (mimeType && !matchesAnyMimeType(mimeType, allowedMimeTypes)) {
        throw new APIError(
          `File type "${mimeType}" is not allowed. Allowed types: ${allowedMimeTypes.join(', ')}`,
          400,
        )
      }

      // Check file size
      const filesize = uploadDoc.filesize as number
      if (filesize && filesize > maxFileSize) {
        const maxSizeMB = (maxFileSize / (1024 * 1024)).toFixed(1)
        const filename = uploadDoc.filename ? String(uploadDoc.filename) : String(fileId)
        throw new APIError(
          `File "${filename}" exceeds the maximum size of ${maxSizeMB} MB`,
          400,
        )
      }
    }

    return data
  }
}

import type { Config } from 'payload'

import type { LfrsPluginConfig, SanitizedLfrsConfig } from './types.js'

import { createDislikesCollection } from './collections/dislikes.js'
import { createFavouritesCollection } from './collections/favourites.js'
import { createLikesCollection } from './collections/likes.js'
import { createRatingsCollection } from './collections/ratings.js'
import { createRepliesCollection } from './collections/replies.js'
import { createReviewsCollection } from './collections/reviews.js'
import { sanitizePluginConfig } from './defaults.js'
import { createDislikeEndpoint } from './endpoints/dislike.js'
import { createDistributionEndpoint } from './endpoints/distribution.js'
import { createFavouriteEndpoint } from './endpoints/favourite.js'
import { createInteractionsEndpoint } from './endpoints/interactions.js'
import { createLikeEndpoint } from './endpoints/like.js'
import { createRateEndpoint } from './endpoints/rate.js'
import { createReplyEndpoint, deleteReplyEndpoint } from './endpoints/reply.js'
import { createReviewEndpoint } from './endpoints/review.js'
import { createStatusEndpoint } from './endpoints/status.js'
import { createAggregateFields } from './fields/aggregateFields.js'
import { createJoinFields } from './fields/joinFields.js'
import { createCascadeDelete } from './hooks/cascadeDelete.js'
import { resolveReviewMedia } from './utilities/resolveReviewMedia.js'

/**
 * The main LFRs plugin function.
 *
 * Uses the standard Payload plugin curried pattern:
 * `(pluginOptions) => (config) => Config`
 */
export const payloadLfRs =
  (pluginOptions: LfrsPluginConfig) =>
  (config: Config): Config => {
    // Sanitize and validate all plugin options
    const sanitized: SanitizedLfrsConfig = sanitizePluginConfig(pluginOptions)

    // Validate review media config against the Payload config (build-time check)
    const resolvedMedia = resolveReviewMedia(sanitized.reviewMedia, config)
    sanitized.reviewMedia = resolvedMedia
    sanitized.mediaEnabled = resolvedMedia !== null

    if (!config.collections) {
      config.collections = []
    }

    // ── Add plugin-managed interaction collections ──────────────────────────
    config.collections.push(createLikesCollection(sanitized))

    if (sanitized.dislikesEnabled) {
      config.collections.push(createDislikesCollection(sanitized))
    }

    config.collections.push(createFavouritesCollection(sanitized))
    config.collections.push(createRatingsCollection(sanitized))
    config.collections.push(createReviewsCollection(sanitized))

    if (sanitized.repliesEnabled) {
      config.collections.push(createRepliesCollection(sanitized))
    }

    // ── Inject aggregate fields and join fields into target collections ─────
    config.collections = config.collections.map((collection) => {
      const collectionOptions = sanitized.collections[collection.slug]

      if (!collectionOptions) {
        // Not a target collection — skip
        return collection
      }

      // Add the lfrs aggregate group field
      const aggregateField = createAggregateFields(collectionOptions, sanitized)

      // Add join fields for admin panel reverse relationships
      const joinFields = createJoinFields(collection.slug, collectionOptions, sanitized)

      return {
        ...collection,
        fields: [...(collection.fields || []), aggregateField, ...joinFields],
      }
    })

    /**
     * If the plugin is disabled, we still keep added collections/fields
     * so the database schema is consistent (important for migrations).
     * But we skip endpoints, hooks, and UI components.
     */
    if (sanitized.disabled) {
      return config
    }

    // ── Phase 3: Wire cascade delete hooks into target collections ──────────
    // (Interaction collection hooks are handled in their own factory functions)
    config.collections = config.collections.map((collection) => {
      if (!sanitized.collections[collection.slug]) {
        return collection
      }

      return {
        ...collection,
        hooks: {
          ...(collection.hooks || {}),
          afterDelete: [
            createCascadeDelete(sanitized, collection.slug),
            ...(collection.hooks?.afterDelete || []),
          ],
        },
      }
    })

    // ── Phase 4: Endpoints will be mounted here ──────────────────────────────
    if (!config.endpoints) {
      config.endpoints = []
    }

    config.endpoints.push(
      {
        handler: createLikeEndpoint(sanitized),
        method: 'post',
        path: '/lfrs/like',
      },
      {
        handler: createFavouriteEndpoint(sanitized),
        method: 'post',
        path: '/lfrs/favourite',
      },
      {
        handler: createRateEndpoint(sanitized),
        method: 'post',
        path: '/lfrs/rate',
      },
      {
        handler: createReviewEndpoint(sanitized),
        method: 'post',
        path: '/lfrs/review',
      },
      {
        handler: createReplyEndpoint(sanitized),
        method: 'post',
        path: '/lfrs/reply',
      },
      {
        handler: deleteReplyEndpoint(sanitized),
        method: 'delete',
        path: '/lfrs/reply',
      },
      {
        handler: createStatusEndpoint(sanitized),
        method: 'get',
        path: '/lfrs/status',
      },
      {
        handler: createInteractionsEndpoint(sanitized),
        method: 'get',
        path: '/lfrs/interactions',
      },
      {
        handler: createDistributionEndpoint(sanitized),
        method: 'get',
        path: '/lfrs/distribution',
      },
    )

    if (sanitized.dislikesEnabled) {
      config.endpoints.push({
        handler: createDislikeEndpoint(sanitized),
        method: 'post',
        path: '/lfrs/dislike',
      })
    }

    // ── Phase 7: Admin UI components will be wired here ──────────────────────
    if (!config.admin) {
      config.admin = {}
    }
    if (!config.admin.components) {
      config.admin.components = {}
    }
    if (!config.admin.components.views) {
      config.admin.components.views = {}
    }

    if (sanitized.reviewModeration) {
      config.admin.components.views.lfrsModeration = {
        Component: 'payload-lfrs/admin#ReviewModerationView',
        exact: true,
        path: '/lfrs-moderation',
      } as any
    }

    return config
  }
